mapper.select:
        SELECT
           t1.id,
           t1.order_sn,
           t1.total_amount,
           t1.payment_amount,
           t1.payment_method,
           t1.status,
           t1.total_amount,
           t1.total_quantity,
           t1.create_time,
           t1.member_id,
           t1.source,
           t1.remark
        FROM
            oms_order t1


                AND
                (
                t1.order_sn like  concat('%',#{queryParams.keywords},'%')
                OR CAST(t1.id AS CHAR) LIKE CONCAT('%', #{queryParams.keywords}, '%')
                )



                AND t1.status= #{queryParams.status}



                AND t1.create_time >= #{queryParams.startTime}



                AND t1.create_time <= #{queryParams.endTime}




                AND t1.payment_method = #{queryParams.payType}




                AND t1.source = #{queryParams.orderType}



                AND t1.total_amount >= #{queryParams.minAmount}



                AND t1.create_time <= #{queryParams.maxAmount}



                AND t1.source = #{queryParams.source}



--         ORDER BY
--             t1.create_time DESC

SELECT status, COUNT(*) as count FROM oms_order
deleted = 0
AND create_time >= #{queryParams.startTime}
AND create_time <= #{queryParams.endTime}
AND ( order_sn LIKE CONCAT('%', #{queryParams.keywords}, '%') OR CAST(id AS CHAR) LIKE CONCAT('%', #{queryParams.keywords}, '%') OR user_phone LIKE CONCAT('%', #{queryParams.keywords}, '%') )
GROUP BY status

SELECT COUNT(*)
FROM oms_order

    deleted = 0



        AND status = #{queryParams.status}




        AND create_time >= #{queryParams.startTime }


        AND create_time <= #{queryParams.endTime }




        AND (
        order_sn LIKE CONCAT('%', #{queryParams.keywords}, '%')
        OR CAST(id AS CHAR) LIKE CONCAT('%', #{queryParams.keywords}, '%')
        OR user_phone LIKE CONCAT('%', #{queryParams.keywords}, '%')
        )

SELECT COUNT(*)
FROM oms_order

    deleted = 0



        AND status IN

            #{status}





        AND create_time >= #{queryParams.startTime}


        AND create_time <= #{queryParams.endTime}




        AND (
        order_sn LIKE CONCAT('%', #{queryParams.keywords}, '%')
        OR CAST(id AS CHAR) LIKE CONCAT('%', #{queryParams.keywords}, '%')
        OR user_phone LIKE CONCAT('%', #{queryParams.keywords}, '%')
        )

SELECT COALESCE(SUM(payment_amount), 0)
FROM oms_order

    deleted = 0
    AND status IN (2, 3, 4)  



        AND status = #{queryParams.status}





        AND create_time >= #{queryParams.startTime}


        AND create_time <= #{queryParams.endTime}




        AND (
        order_sn LIKE CONCAT('%', #{queryParams.keywords}, '%')
        OR CAST(id AS CHAR) LIKE CONCAT('%', #{queryParams.keywords}, '%')
        OR user_phone LIKE CONCAT('%', #{queryParams.keywords}, '%')
        )
